import { FormControl } from '@material-ui/core'
import { Select } from '@material-ui/core'
import { TextField } from '@material-ui/core'
import { MenuItem } from '@material-ui/core'
import { InputLabel } from '@material-ui/core'
import { Grid } from '@material-ui/core'
import React from 'react'
import styled from 'styled-components'
import { motion, useAnimation  } from 'framer-motion'
import { useInView } from 'react-intersection-observer';
import { useEffect } from 'react'

export default function FormSection({valueFull, domain, setDomain, option, setOption, email, setEmail, message, setMessage, name, setName, phone, setPhone, userEmail, setUserEmail}) {

    const controls = useAnimation();
    const { ref, inView } = useInView({
        "triggerOnce": true
    });

    useEffect(() => {
        if (inView) {
          controls.start('visible');
        }
        if (!inView) {
          controls.start('hidden');
        }
      }, [controls, inView]);
    
      const wrapperVariants = {
          hidden: {scale: 0},
          visible: i => ({
              scale: 1,
              transition: {
                  duration: 0.5,
                  delay: i * 0.1
              }
          })
      }
    
    return (
        <Container ref={ref}>
            <Grid container spacing={1}>
                <Grid
                component={motion.div}
                custom={0}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField
                        required
                        id="name"
                        name="name"
                        fullWidth
                        label="Nume"
                        variant="filled"
                        type="text"
                        value={name}
                        onChange={e => setName(e.target.value)}  
                    />
                </Grid>
                <Grid 
                component={motion.div}
                custom={1}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField
                        required
                        id="userEmail"
                        name="user email"
                        fullWidth
                        label="Email"
                        variant="filled"
                        type="email"
                        value={userEmail}
                        onChange={e => setUserEmail(e.target.value)}  
                    />
                </Grid>
                <Grid 
                component={motion.div}
                custom={2}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField
                        required
                        id="phoneNumber"
                        name="phone number"
                        fullWidth
                        label="Număr telefon"
                        variant="filled"
                        type="number"
                        value={phone}
                        onChange={e => setPhone(e.target.value)}  
                    />
                </Grid>
                <Grid 
                component={motion.div}
                custom={3}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={8}>
                    <TextField  
                        id="domain-name" 
                        name="domain"
                        label="Denumire domeniu" 
                        type="text" 
                        fullWidth 
                        variant="filled"
                        value={domain}
                        onChange={e => setDomain(e.target.value)}
                    />
                </Grid>
                <Grid 
                component={motion.div}
                custom={3}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={4}>
                    <FormControl fullWidth>
                        <InputLabel id="demo-simple-select-helper-label">Alege domeniu</InputLabel>
                        <Select
                            name="options"
                            variant="filled"
                            labelId="demo-simple-select-helper-label"
                            id="demo-simple-select-helper"
                            required
                            value={option}
                            onChange={e => setOption(e.target.value)}
                        >
                            <MenuItem value="">
                                <em>None</em>
                            </MenuItem>
                            <MenuItem value={0}>▸ github.io/ - 0 RON/an</MenuItem>
                            <MenuItem value={40}>▸ .ro/altele - 40 RON/an</MenuItem>
                            <MenuItem value={50}>▸ .com - 50 RON/an</MenuItem>
                            <MenuItem value={80}>▸ .info - 80 RON/an</MenuItem>
                        </Select>
                    </FormControl>
                </Grid>
                <Grid 
                component={motion.div}
                custom={4}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField  
                        name="email"
                        label="Business Email - 26 RON/lună"
                        placeholder="emailultău@domeniultău.ro" 
                        type="email" 
                        value={email}
                        onChange={e => setEmail(e.target.value)}
                        fullWidth 
                        variant="filled"/>
                </Grid>
                <Grid 
                component={motion.div}
                custom={5}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField  
                        name="ssl certificate"
                        label="Secure Sockets Layer"
                        placeholder="emailultău@demeniultău.ro" 
                        type="text" 
                        fullWidth 
                        value={valueFull === 'full'? "Certificat SSL - 50 RON/an" : 'Fără certificat SSL'}
                        variant="filled"
                        disabled/>
                </Grid>
                <Grid 
                component={motion.div}
                custom={6}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField
                        fullWidth
                        name="description"
                        id="standard-multiline-static"
                        label="Descriere website/adaugă linkuri"
                        multiline
                        rows={6}
                        spellCheck={false}
                        variant="filled"
                        required
                        value={message}
                        onChange={(e) => setMessage(e.target.value)}
                    />
                </Grid>
            </Grid>
        </Container>
    )
}


const Container = styled.section`
    width: 700px;
    max-width: 96vw;
    margin: 100px auto 20px;
`