import styled from 'styled-components';
import { Link } from 'react-router-dom';
import FacebookIcon from '@material-ui/icons/Facebook';
import TwitterIcon from '@material-ui/icons/Twitter';
import YouTubeIcon from '@material-ui/icons/YouTube';
import GitHubIcon from '@material-ui/icons/GitHub';
import logo from '../images/codmitu.svg'


export default function Footer() {
    return (
        <FooterContainer>
            <FooterWrapper>
                <SocialMedia>
                    <SocialMediaWrapper>
                        <SocialLogo onClick={() => window.scrollTo(0, 0)} to="">
                            <img src={logo} alt="logo"/>
                        </SocialLogo>
                        <WebsiteRights>codmitu.com &copy;{new Date().getFullYear()} All rights reserved.</WebsiteRights>
                        <SocialIcons>
                            <SocialIconLink href="https://www.facebook.com/profile.php?id=100069009977273" target="_blank" aria-label="Facebook">
                                <FacebookIcon />
                            </SocialIconLink>
                            <SocialIconLink href="https://www.youtube.com/channel/UCcevIRmsh-gsiPWw7z45cog" target="_blank" aria-label="Youtube">
                                <YouTubeIcon />
                            </SocialIconLink>
                            <SocialIconLink href="https://twitter.com/codmitu" target="_blank" aria-label="Twitter">
                                <TwitterIcon />
                            </SocialIconLink>
                            <SocialIconLink href="https://github.com/codmitu" target="_blank" aria-label="Github">
                                <GitHubIcon />
                            </SocialIconLink>
                            <SocialIconLink href="https://codepen.io/codmitu" target="_blank" aria-label="Codepen">
                                <span className="iconify" data-icon="fe:codepen"></span>
                            </SocialIconLink>
                        </SocialIcons>
                    </SocialMediaWrapper>
                </SocialMedia>
            </FooterWrapper>
        </FooterContainer>
    )
}






const FooterContainer = styled.footer`
    background-color: #f5f5f5;
`
const FooterWrapper = styled.div`
    padding: 48px 24px;
    height: 300px;
    gap: 50px;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    max-width: 1100px;
    margin: 0 auto;
    @media screen and (max-width: 800px) {
        height: 200px;
    }
`

const SocialMedia = styled.section`
    max-width: 1000px;
    width: 100%;
`
const SocialMediaWrapper = styled.div`
    display: flex;
    justify-content: space-between;
    align-items: center;
    max-width: 1100px;
    margin: 40px auto 0 auto;
    @media screen and (max-width: 820px) {
        flex-direction: column;
    }
`
const SocialLogo = styled(Link)`
    cursor: pointer;
    text-decoration: none;
    >img {
        height: 70px;
    }
`
const WebsiteRights = styled.small`
    color: #242424;
    @media screen and (max-width: 820px) {
        margin-bottom: 20px;
    }
`
const SocialIcons = styled.div`
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 240px;
`
const SocialIconLink = styled.a`
    color: #313131;
    font-size: 24px;
    &[aria-label="Facebook"] {
        &:hover {
            color: #4064ac;
        }
    }
    &[aria-label="Youtube"] {
        &:hover {
            color: #f70000;
        }
    }
    &[aria-label="Twitter"] {
        &:hover {
            color: #1d9ce9;
        }
    }
    &[aria-label="Github"] {
        &:hover {
            color: #a200ff;
        }
    }
    &[aria-label="Codepen"] {
        &:hover {
            color: #6d6d6d;
        }
    }
`
